     1→/**
     2→ * TimelineHeader - Displays date labels synced with canvas panX
     3→ *
     4→ * Features:
     5→ * - Adaptive granularity based on zoom level:
     6→ *   - Low zoom (< 0.5): Years
     7→ *   - Medium zoom (0.5-1.5): Months
     8→ *   - High zoom (1.5-3.0): Weeks
     9→ *   - Very high zoom (> 3.0): Days
    10→ * - Labels positioned to align with canvas content
    11→ * - Labels don't overlap (spacing adjusted based on zoom)
    12→ */
    13→
    14→import { useMemo } from 'react';
    15→import { DEFAULT_VIEW_CONFIG, DEFAULT_DATASET_META } from '../data/types';
    16→
    17→interface TimelineHeaderProps {
    18→  /** Left edge of the visible viewport in world X coordinates */
    19→  viewportLeftX: number;
    20→  /** Right edge of the visible viewport in world X coordinates */
    21→  viewportRightX: number;
    22→  /** Current zoom level */
    23→  zoom: number;
    24→  /** Width of the sidebar (to offset the timeline) */
    25→  sidebarWidth: number;
    26→}
    27→
    28→const { pxPerDay } = DEFAULT_VIEW_CONFIG;
    29→const START_DATE = new Date(DEFAULT_DATASET_META.startDate);
    30→
    31→// Format helpers
    32→const formatYear = (date: Date) => date.getFullYear().toString();
    33→const formatMonth = (date: Date) =>
    34→  date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
    35→const formatWeek = (date: Date) =>
    36→  date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    37→const formatDay = (date: Date) =>
    38→  date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
    39→
    40→/**
    41→ * Calculate the appropriate granularity based on zoom level
    42→ */
    43→type Granularity = 'year' | 'month' | 'week' | 'day';
    44→
    45→function getGranularity(zoom: number): Granularity {
    46→  if (zoom < 0.5) return 'year';
    47→  if (zoom < 1.5) return 'month';
    48→  if (zoom < 3.0) return 'week';
    49→  return 'day';
    50→}
    51→
    52→/**
    53→ * Get the minimum pixel spacing between labels for each granularity
    54→ */
    55→function getMinLabelSpacing(granularity: Granularity): number {
    56→  switch (granularity) {
    57→    case 'year':
    58→      return 80;
    59→    case 'month':
    60→      return 70;
    61→    case 'week':
    62→      return 60;
    63→    case 'day':
    64→      return 50;
    65→  }
    66→}
    67→
    68→/**
    69→ * Convert world X coordinate to day offset from start date
    70→ */
    71→function worldXToDayOffset(worldX: number): number {
    72→  return Math.floor(worldX / pxPerDay);
    73→}
    74→
    75→/**
    76→ * Convert day offset to world X coordinate
    77→ */
    78→function dayOffsetToWorldX(dayOffset: number): number {
    79→  return dayOffset * pxPerDay;
    80→}
    81→
    82→/**
    83→ * Add days to a date
    84→ */
    85→function addDays(date: Date, days: number): Date {
    86→  const result = new Date(date);
    87→  result.setDate(result.getDate() + days);
    88→  return result;
    89→}
    90→
    91→/**
    92→ * Get the start of a time unit
    93→ */
    94→function getUnitStart(date: Date, granularity: Granularity): Date {
    95→  const result = new Date(date);
    96→  result.setHours(0, 0, 0, 0);
    97→
    98→  switch (granularity) {
    99→    case 'year':
   100→      result.setMonth(0, 1);
   101→      break;
   102→    case 'month':
   103→      result.setDate(1);
   104→      break;
   105→    case 'week':
   106→      // Start of week (Sunday)
   107→      const day = result.getDay();
   108→      result.setDate(result.getDate() - day);
   109→      break;
   110→    case 'day':
   111→      // Already at start of day
   112→      break;
   113→  }
   114→
   115→  return result;
   116→}
   117→
   118→/**
   119→ * Get days until next unit
   120→ */
   121→function getDaysPerUnit(granularity: Granularity): number {
   122→  switch (granularity) {
   123→    case 'year':
   124→      return 365;
   125→    case 'month':
   126→      return 30;
   127→    case 'week':
   128→      return 7;
   129→    case 'day':
   130→      return 1;
   131→  }
   132→}
   133→
   134→/**
   135→ * Advance to next unit
   136→ */
   137→function advanceUnit(date: Date, granularity: Granularity): Date {
   138→  const result = new Date(date);
   139→
   140→  switch (granularity) {
   141→    case 'year':
   142→      result.setFullYear(result.getFullYear() + 1);
   143→      break;
   144→    case 'month':
   145→      result.setMonth(result.getMonth() + 1);
   146→      break;
   147→    case 'week':
   148→      result.setDate(result.getDate() + 7);
   149→      break;
   150→    case 'day':
   151→      result.setDate(result.getDate() + 1);
   152→      break;
   153→  }
   154→
   155→  return result;
   156→}
   157→
   158→/**
   159→ * Format date based on granularity
   160→ */
   161→function formatDate(date: Date, granularity: Granularity): string {
   162→  switch (granularity) {
   163→    case 'year':
   164→      return formatYear(date);
   165→    case 'month':
   166→      return formatMonth(date);
   167→    case 'week':
   168→      return formatWeek(date);
   169→    case 'day':
   170→      return formatDay(date);
   171→  }
   172→}
   173→
   174→interface TimeLabel {
   175→  dayOffset: number;
   176→  worldX: number;
   177→  label: string;
   178→  isMinor: boolean; // For smaller tick marks
   179→}
   180→
   181→/**
   182→ * Generate labels for the visible viewport
   183→ */
   184→function generateLabels(
   185→  viewportLeftX: number,
   186→  viewportRightX: number,
   187→  granularity: Granularity
   188→): TimeLabel[] {
   189→  const labels: TimeLabel[] = [];
   190→
   191→  // Add padding to viewport to show labels near edges
   192→  const padding = getDaysPerUnit(granularity) * pxPerDay * 2;
   193→  const startDayOffset = worldXToDayOffset(viewportLeftX - padding);
   194→  const endDayOffset = worldXToDayOffset(viewportRightX + padding);
   195→
   196→  // Convert to dates
   197→  const startDate = addDays(START_DATE, startDayOffset);
   198→  const endDate = addDays(START_DATE, endDayOffset);
   199→
   200→  // Find the first unit boundary at or before startDate
   201→  let currentDate = getUnitStart(startDate, granularity);
   202→
   203→  // If currentDate is before START_DATE, advance to START_DATE
   204→  if (currentDate < START_DATE) {
   205→    currentDate = getUnitStart(START_DATE, granularity);
   206→    if (currentDate < START_DATE) {
   207→      currentDate = advanceUnit(currentDate, granularity);
   208→    }
   209→  }
   210→
   211→  // Generate labels until we pass endDate
   212→  while (currentDate <= endDate) {
