/**
 * PerfMonitor - Performance monitoring and logging for WebGL canvas
 *
 * Features:
 * - Visual panel with FPS, MS, MB, GPU, draw calls, triangles (via r3f-perf)
 * - Detailed logging system for programmatic analysis
 * - Session recording for before/after comparisons
 * - Accessible via window.__PERF_* globals for AI/human analysis
 *
 * Usage:
 * - Press 'P' to toggle the visual panel
 * - window.__PERF_LOG__ - access current log buffer
 * - window.__PERF_EXPORT__() - export full log as JSON
 * - window.__PERF_START_SESSION__(name) - start recording session
 * - window.__PERF_STOP_SESSION__() - stop and get aggregated metrics
 */

import { useEffect, useRef, useCallback } from 'react';
import { Perf, usePerf } from 'r3f-perf';
import { useFrame } from '@react-three/fiber';

// ─────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────

interface PerfLogEntry {
  timestamp: number;
  fps: { avg: number; min: number; max: number };
  ms: { avg: number; min: number; max: number };
  memory: number;
  drawCalls: number;
  triangles: number;
  event: PerfEvent;
}

type PerfEvent = 'idle' | 'panning' | 'zooming' | 'animating' | 'lod_transition';

interface PerfSession {
  name: string;
  startTime: number;
  entries: PerfLogEntry[];
}

interface PerfSessionResult {
  name: string;
  duration: number;
  frameCount: number;
  fps: {
    avg: number;
    min: number;
    max: number;
    p1: number;
    p99: number;
  };
  ms: {
    avg: number;
    min: number;
    max: number;
  };
  memory: {
    start: number;
    end: number;
    delta: number;
  };
  framesBelow30: number;
  framesBelow60: number;
}

// ─────────────────────────────────────────────────────────────
// LOGGING SYSTEM
// ─────────────────────────────────────────────────────────────

const LOG_BUFFER_SIZE = 3600; // 60 seconds at 60fps
const LOG_SAMPLE_INTERVAL = 60; // Log every 60 frames (1 second)

class PerfLogger {
  private buffer: PerfLogEntry[] = [];
  private frameCount = 0;
  private currentSession: PerfSession | null = null;
  private currentEvent: PerfEvent = 'idle';

  // Frame metrics accumulator
  private fpsValues: number[] = [];
  private msValues: number[] = [];

  setEvent(event: PerfEvent): void {
    this.currentEvent = event;
  }

  recordFrame(fps: number, ms: number, memory: number, drawCalls: number, triangles: number): void {
    this.frameCount++;
    this.fpsValues.push(fps);
    this.msValues.push(ms);

    // Log every N frames
    if (this.frameCount % LOG_SAMPLE_INTERVAL === 0) {
      const entry = this.createLogEntry(memory, drawCalls, triangles);
      this.addEntry(entry);
      this.fpsValues = [];
      this.msValues = [];
    }
  }

  private createLogEntry(memory: number, drawCalls: number, triangles: number): PerfLogEntry {
    const fpsArr = this.fpsValues.length > 0 ? this.fpsValues : [0];
    const msArr = this.msValues.length > 0 ? this.msValues : [0];

    return {
      timestamp: Date.now(),
      fps: {
        avg: this.average(fpsArr),
        min: Math.min(...fpsArr),
        max: Math.max(...fpsArr),
      },
      ms: {
        avg: this.average(msArr),
        min: Math.min(...msArr),
        max: Math.max(...msArr),
      },
      memory,
      drawCalls,
      triangles,
      event: this.currentEvent,
    };
  }

  private addEntry(entry: PerfLogEntry): void {
    this.buffer.push(entry);
    if (this.buffer.length > LOG_BUFFER_SIZE) {
      this.buffer.shift();
    }

    if (this.currentSession) {
      this.currentSession.entries.push(entry);
    }
  }

  private average(arr: number[]): number {
    return arr.reduce((a, b) => a + b, 0) / arr.length;
  }

  private percentile(arr: number[], p: number): number {
    const sorted = [...arr].sort((a, b) => a - b);
    const index = Math.floor((p / 100) * sorted.length);
    return sorted[Math.min(index, sorted.length - 1)] ?? 0;
  }

  getLog(): PerfLogEntry[] {
    return [...this.buffer];
  }

  exportLog(): string {
    return JSON.stringify(this.buffer, null, 2);
  }

  startSession(name: string): void {
    this.currentSession = {
      name,
      startTime: Date.now(),
      entries: [],
    };
  }

  stopSession(): PerfSessionResult | null {
    if (!this.currentSession) return null;

    const session = this.currentSession;
    this.currentSession = null;

    if (session.entries.length === 0) {
      return {
        name: session.name,
        duration: 0,
        frameCount: 0,
        fps: { avg: 0, min: 0, max: 0, p1: 0, p99: 0 },
        ms: { avg: 0, min: 0, max: 0 },
        memory: { start: 0, end: 0, delta: 0 },
        framesBelow30: 0,
        framesBelow60: 0,
      };
    }

    const fpsValues = session.entries.map((e) => e.fps.avg);
    const msValues = session.entries.map((e) => e.ms.avg);

    const framesBelow30 = fpsValues.filter((fps) => fps < 30).length;
    const framesBelow60 = fpsValues.filter((fps) => fps < 60).length;

    return {
      name: session.name,
      duration: (Date.now() - session.startTime) / 1000,
      frameCount: session.entries.length * LOG_SAMPLE_INTERVAL,
      fps: {
        avg: this.average(fpsValues),
        min: Math.min(...fpsValues),
        max: Math.max(...fpsValues),
        p1: this.percentile(fpsValues, 1),
        p99: this.percentile(fpsValues, 99),
      },
      ms: {
        avg: this.average(msValues),
        min: Math.min(...msValues),
        max: Math.max(...msValues),
      },
      memory: {
        start: session.entries[0]?.memory ?? 0,
        end: session.entries[session.entries.length - 1]?.memory ?? 0,
        delta:
          (session.entries[session.entries.length - 1]?.memory ?? 0) -
          (session.entries[0]?.memory ?? 0),
      },
      framesBelow30,
      framesBelow60,
    };
  }

  isRecording(): boolean {
    return this.currentSession !== null;
  }

  getSessionName(): string | null {
    return this.currentSession?.name ?? null;
  }
}

// Singleton logger instance
const perfLogger = new PerfLogger();

// ─────────────────────────────────────────────────────────────
// GLOBAL API
// ─────────────────────────────────────────────────────────────

declare global {
  interface Window {
    __PERF_LOG__: PerfLogEntry[];
    __PERF_EXPORT__: () => string;
    __PERF_START_SESSION__: (name: string) => void;
    __PERF_STOP_SESSION__: () => PerfSessionResult | null;
    __PERF_SET_EVENT__: (event: PerfEvent) => void;
    __PERF_IS_RECORDING__: () => boolean;
  }
}

// Register global API
if (typeof window !== 'undefined') {
  Object.defineProperty(window, '__PERF_LOG__', {
    get: () => perfLogger.getLog(),
    configurable: true,
  });
  window.__PERF_EXPORT__ = () => perfLogger.exportLog();
  window.__PERF_START_SESSION__ = (name: string) => perfLogger.startSession(name);
  window.__PERF_STOP_SESSION__ = () => perfLogger.stopSession();
  window.__PERF_SET_EVENT__ = (event: PerfEvent) => perfLogger.setEvent(event);
  window.__PERF_IS_RECORDING__ = () => perfLogger.isRecording();
}

// ─────────────────────────────────────────────────────────────
// PERF LOGGER COMPONENT (inside Canvas)
// ─────────────────────────────────────────────────────────────

function PerfLoggerComponent(): null {
  const perfData = usePerf();

  useFrame(() => {
    if (perfData) {
      const { fps, gl } = perfData.log as {
        fps: number;
        gl: { calls: number; triangles: number };
      };
      const ms = fps > 0 ? 1000 / fps : 0;
      const memory = (performance as unknown as { memory?: { usedJSHeapSize: number } }).memory
        ?.usedJSHeapSize ?? 0;

      perfLogger.recordFrame(
        fps,
        ms,
        memory / (1024 * 1024), // Convert to MB
        gl?.calls ?? 0,
        gl?.triangles ?? 0
      );
    }
  });

  return null;
}

// ─────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────

interface PerfMonitorProps {
  /** Whether to show the visual panel */
  visible?: boolean;
  /** Position of the panel */
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
  /** Whether to show detailed metrics (deep analyze) */
  deepAnalyze?: boolean;
  /** Callback when visibility changes */
  onVisibilityChange?: (visible: boolean) => void;
}

export function PerfMonitor({
  visible = true,
  position = 'top-right',
  deepAnalyze = true,
}: PerfMonitorProps): JSX.Element | null {
  // Convert position to r3f-perf format
  const perfPosition = position.replace('-', '') as
    | 'topleft'
    | 'topright'
    | 'bottomleft'
    | 'bottomright';

  if (!visible) {
    // Still log even when panel is hidden
    return <PerfLoggerComponent />;
  }

  return (
    <>
      <Perf
        position={perfPosition}
        deepAnalyze={deepAnalyze}
        showGraph={true}
        minimal={false}
        matrixUpdate={true}
        overClock={true}
        style={{
          // Ensure it's visible and readable
          fontSize: '11px',
          fontFamily: 'monospace',
        }}
      />
      <PerfLoggerComponent />
    </>
  );
}

// ─────────────────────────────────────────────────────────────
// KEYBOARD TOGGLE HOOK
// ─────────────────────────────────────────────────────────────

/**
 * Hook to toggle perf monitor visibility with keyboard
 */
export function usePerfToggle(initialVisible = true): [boolean, () => void] {
  const visibleRef = useRef(initialVisible);
  const [visible, setVisible] = useState(initialVisible);

  const toggle = useCallback(() => {
    visibleRef.current = !visibleRef.current;
    setVisible(visibleRef.current);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Toggle with 'P' key (not when typing in inputs)
      if (
        e.key === 'p' &&
        !e.ctrlKey &&
        !e.metaKey &&
        !e.altKey &&
        !(e.target instanceof HTMLInputElement) &&
        !(e.target instanceof HTMLTextAreaElement)
      ) {
        toggle();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggle]);

  return [visible, toggle];
}

// ─────────────────────────────────────────────────────────────
// EVENT TRACKING HOOK
// ─────────────────────────────────────────────────────────────

/**
 * Hook to track current canvas event for logging
 */
export function usePerfEvent(): (event: PerfEvent) => void {
  return useCallback((event: PerfEvent) => {
    perfLogger.setEvent(event);
  }, []);
}

// Re-export types for external use
export type { PerfEvent, PerfLogEntry, PerfSessionResult };

// Need to add useState import
import { useState } from 'react';

