    return {
      name: session.name,
      duration: (Date.now() - session.startTime) / 1000,
      frameCount: session.entries.length * LOG_SAMPLE_INTERVAL,
      fps: {
        avg: this.average(fpsValues),
        min: Math.min(...fpsValues),
        max: Math.max(...fpsValues),
        p1: this.percentile(fpsValues, 1),
        p99: this.percentile(fpsValues, 99),
      },
      ms: {
        avg: this.average(msValues),
        min: Math.min(...msValues),
        max: Math.max(...msValues),
      },
      memory: {
        start: session.entries[0]?.memory ?? 0,
        end: session.entries[session.entries.length - 1]?.memory ?? 0,
        delta:
          (session.entries[session.entries.length - 1]?.memory ?? 0) -
          (session.entries[0]?.memory ?? 0),
      },
      framesBelow30,
      framesBelow60,
    };
  }

  isRecording(): boolean {
    return this.currentSession !== null;
  }

  getSessionName(): string | null {
    return this.currentSession?.name ?? null;
  }
}

// Singleton logger instance
const perfLogger = new PerfLogger();

// ─────────────────────────────────────────────────────────────
// GLOBAL API
// ─────────────────────────────────────────────────────────────

declare global {
  interface Window {
    __PERF_LOG__: PerfLogEntry[];
    __PERF_EXPORT__: () => string;
    __PERF_START_SESSION__: (name: string) => void;
    __PERF_STOP_SESSION__: () => PerfSessionResult | null;
    __PERF_SET_EVENT__: (event: PerfEvent) => void;
    __PERF_IS_RECORDING__: () => boolean;
  }
}

// Register global API
if (typeof window !== 'undefined') {
  Object.defineProperty(window, '__PERF_LOG__', {
    get: () => perfLogger.getLog(),
    configurable: true,
  });
  window.__PERF_EXPORT__ = () => perfLogger.exportLog();
  window.__PERF_START_SESSION__ = (name: string) => perfLogger.startSession(name);
  window.__PERF_STOP_SESSION__ = () => perfLogger.stopSession();
  window.__PERF_SET_EVENT__ = (event: PerfEvent) => perfLogger.setEvent(event);
  window.__PERF_IS_RECORDING__ = () => perfLogger.isRecording();
}

// ─────────────────────────────────────────────────────────────
// PERF LOGGER COMPONENT (inside Canvas)
// ─────────────────────────────────────────────────────────────

function PerfLoggerComponent(): null {
  const perfData = usePerf();

  useFrame(() => {
    if (perfData) {
      const { fps, gl } = perfData.log as {
        fps: number;
        gl: { calls: number; triangles: number };
      };
      const ms = fps > 0 ? 1000 / fps : 0;
      const memory = (performance as unknown as { memory?: { usedJSHeapSize: number } }).memory
        ?.usedJSHeapSize ?? 0;

      perfLogger.recordFrame(
        fps,
        ms,
        memory / (1024 * 1024), // Convert to MB
        gl?.calls ?? 0,
        gl?.triangles ?? 0
      );
    }
  });

  return null;
}

// ─────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────

interface PerfMonitorProps {
  /** Whether to show the visual panel */
  visible?: boolean;
  /** Position of the panel */
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
  /** Whether to show detailed metrics (deep analyze) */
  deepAnalyze?: boolean;
  /** Callback when visibility changes */
  onVisibilityChange?: (visible: boolean) => void;
}

export function PerfMonitor({
  visible = true,
  position = 'top-right',
  deepAnalyze = true,
}: PerfMonitorProps): JSX.Element | null {
  // Convert position to r3f-perf format
  const perfPosition = position.replace('-', '') as
    | 'topleft'
    | 'topright'
    | 'bottomleft'
    | 'bottomright';

  if (!visible) {
    // Still log even when panel is hidden
    return <PerfLoggerComponent />;
  }

  return (
    <>
      <Perf
        position={perfPosition}
        deepAnalyze={deepAnalyze}
        showGraph={true}
        minimal={false}
        matrixUpdate={true}
        overClock={true}
        style={{
          // Ensure it's visible and readable
          fontSize: '11px',
          fontFamily: 'monospace',
        }}
      />
      <PerfLoggerComponent />
    </>
  );
}

// ─────────────────────────────────────────────────────────────
// KEYBOARD TOGGLE HOOK
// ─────────────────────────────────────────────────────────────

/**
 * Hook to toggle perf monitor visibility with keyboard
 */
export function usePerfToggle(initialVisible = true): [boolean, () => void] {
  const visibleRef = useRef(initialVisible);
  const [visible, setVisible] = useState(initialVisible);

  const toggle = useCallback(() => {
    visibleRef.current = !visibleRef.current;
    setVisible(visibleRef.current);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Toggle with 'P' key (not when typing in inputs)
      if (
        e.key === 'p' &&
        !e.ctrlKey &&
        !e.metaKey &&
        !e.altKey &&
        !(e.target instanceof HTMLInputElement) &&
        !(e.target instanceof HTMLTextAreaElement)
      ) {
        toggle();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggle]);

  return [visible, toggle];
}

// ─────────────────────────────────────────────────────────────
// EVENT TRACKING HOOK
// ─────────────────────────────────────────────────────────────

/**
 * Hook to track current canvas event for logging
 */
export function usePerfEvent(): (event: PerfEvent) => void {
  return useCallback((event: PerfEvent) => {
    perfLogger.setEvent(event);
  }, []);
}

// Re-export types for external use
export type { PerfEvent, PerfLogEntry, PerfSessionResult };

// Need to add useState import
import { useState } from 'react';

